// Приводим сообщения из разных каналов к единому формату
const item = items[0];
const body = item.json;

let userId, text, channel;

// ВКонтакте
if (body.type === 'message_new' && body.object?.message) {
  userId = 'vk_' + body.object.message.from_id;
  text = body.object.message.text;
  channel = 'vk';
}
// Макс (Max.ru)
else if (body.message && body.message.body) {
  userId = 'max_' + body.message.from.user_id;
  text = body.message.body;
  channel = 'max';
}
// Неизвестный формат
else {
  return [];
}

if (!text || text.trim() === '') return [];

return [{ json: { userId, text, channel, rawBody: body } }];

// Загружаем историю диалога для этого пользователя из памяти n8n
// В продакшне замени на Redis или PostgreSQL для надёжности
const userId = items[0].json.userId;
const text = items[0].json.text;
const channel = items[0].json.channel;

// Глобальная переменная для хранения сессий (в рамках одного запуска n8n)
if (!global.sessions) global.sessions = {};
if (!global.sessions[userId]) {
  global.sessions[userId] = {
    history: [],
    stage: 'collecting',
    tz: {}
  };
}

const session = global.sessions[userId];

return [{ json: {
  userId,
  text,
  channel,
  history: session.history,
  stage: session.stage,
  tz: session.tz
}}];

const item = items[0];
const response = item.json;
const userId = item.json.userId || $('Нормализация сообщения').first().json.userId;

// Получаем текст ответа
const content = response.content || [];
const agentText = content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();

// Проверяем нужен ли поиск туров
const searchMatch = agentText.match(/```json([\s\S]*?)```/);
let searchParams = null;
if (searchMatch) {
  try { searchParams = JSON.parse(searchMatch[1].trim()); } catch(e) {}
}

// Проверяем принял ли клиент решение
const isDecision = /передаю вашу заявку менеджеру/i.test(agentText);

// Обновляем историю сессии
if (!global.sessions) global.sessions = {};
if (!global.sessions[userId]) global.sessions[userId] = { history: [], stage: 'collecting', tz: {} };

global.sessions[userId].history.push(
  { role: 'user', content: item.json.text },
  { role: 'assistant', content: agentText }
);

// Ограничиваем историю (последние 20 сообщений)
if (global.sessions[userId].history.length > 20) {
  global.sessions[userId].history = global.sessions[userId].history.slice(-20);
}

// Чистим JSON-блок из ответа клиенту
const cleanText = agentText.replace(/```json[\s\S]*?```/g, '').trim();

return [{ json: {
  userId,
  channel: item.json.channel || 'vk',
  rawBody: item.json.rawBody,
  agentText: cleanText,
  searchParams,
  isDecision,
  needSearch: searchParams !== null
}}];
